var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAC","text":{"KOREA":"뭐지?! 검은 기사는 이곳에 출몰하는 몬스터가 아닐 텐데?","JPN":"なんだ！？　黒い騎士はここに出現するモンスターじゃないはず！","ENG":"Huh?! The black knight shouldn't be spawning here!","TWN":"什麼？！黑騎士應該不是出現在這裡的怪物吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAC","text":{"KOREA":"그새 패치라도 한 건가? 그런 공지는 없었는데?","JPN":"データ更新があったのか？　そんな告知はなかったけど。","ENG":"Was there a patch? But I didn't see any notices?","TWN":"這麼快就更新了嗎？沒有看到相關通知啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRA","text":{"KOREA":"내가 도와주겠다. 곤란한 자를 두고 갈 순 없지.","JPN":"俺が助けてやる。困っている者を見過ごすわけにはいかない。","ENG":"I'll help. I can't ignore someone in need.","TWN":"我來幫你吧，不能丟下有困難的人不管。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAC","text":{"KOREA":"뭐, 뭐야? 난 당신들 도움 따위 필요 없어!","JPN":"な、なんだ？　あんたたちの助けなんかいらない！","ENG":"W-who're you? I don't need your help!","TWN":"什，什麼？我不需要你們的幫忙！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAC","text":{"KOREA":"커헉……!","JPN":"がはっ……！","ENG":"Gah...!","TWN":"咳……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAC","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRA","text":{"KOREA":"말해봐. 당신이 보기에도 우린 영웅이 아닌가?","JPN":"言ってみろ。君も、俺たちは英雄じゃないと思うか？","ENG":"Tell me. Do we not seem like heroes to you?","TWN":"說說看，你覺得我們不是英雄嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAC","text":{"KOREA":"무, 무슨 헛소리야……?!","JPN":"な、なんのことだ……！？","ENG":"W-what are you talking about...?!","TWN":"你……你在胡說什麼……？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAB","text":{"KOREA":"당신, 카운터 유저로군.","JPN":"あんた、カウンターのユーザーだな。","ENG":"You. You're a Counter, aren't you?","TWN":"你是制裁者玩家吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAB","text":{"KOREA":"우린 당신처럼 단 한 순간도 로그아웃하는 일 없이 수련에 몰두하고 있다.","JPN":"俺たちはあんたと違って、ログアウトなしでずっと修行に励んでいる。","ENG":"Unlike you, we've been training nonstop without logging out for even a second.","TWN":"我們像你一樣，哪怕一刻也不曾登出，一直專注於修煉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAB","text":{"KOREA":"먹는 것도, 자는 일도 없이…… 단 한 순간도…….","JPN":"寝ることも、食べることもなく……一瞬も休まず……","ENG":"Not even a second... not to eat, or sleep...","TWN":"沒有吃飯，也沒有睡覺……一刻也沒有……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRA","text":{"KOREA":"그럼에도…… 우린 계속 부정당하고 있어.","JPN":"それなのに……俺たちは否定され続けてるんだ。","ENG":"But still... we keep getting denied.","TWN":"即便如此……我們仍然不斷被否定。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRA","text":{"KOREA":"동경하던 꿈을 이뤄보라고……? 웃기는 소리……!!","JPN":"憧れていた夢を叶える……？　ふざけるな……！！","ENG":"Achieve our dreams...? Ridiculous...!!","TWN":"讓我實現夢寐以求的夢想……？真是笑話……！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"PLAYER_LAGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PLAYER_LAGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAC","text":{"KOREA":"자, 잠깐……!","JPN":"ちょ、ちょっと……！","ENG":"W-wait...!","TWN":"等，等等……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAC","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"리네한테 연락이 왔어. 노멀 플레이어들이 광폭해지고 있대.","JPN":"マリちゃんから連絡があったわ。ノーマルプレイヤーたちが狂暴化してるらしい。","ENG":"I got word from Rinae. The normal players are on a rampage.","TWN":"收到璃奈的通知，普通玩家暴走中。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"카운터즈 레거시의 평판도 좋지 않아. 부정적인 평가가 많아지고 있어.","JPN":"カウンターズ・レガシーの評判も悪化してる。不評レビューが増えているの。","ENG":"Counters Legacy's reputation is getting worse. A lot of negative reviews are being posted.","TWN":"制裁者的遺產的評價也不好，負面評價越來越多了。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"폭주하는 거야……. 오버로드.","JPN":"暴走している……オーバーロードが。","ENG":"Overlord is... going out of control.","TWN":"暴走了嗎……超載。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"이대로 가다간…… 동경을 넘어 다른 걸 비추게 될지도 몰라.","JPN":"このままだと……憧れを通り越して、違うものを映してしまうかもしれない。","ENG":"At this rate... the people might reflect something other than admiration.","TWN":"這樣下去的話……可能會映照出不同於憧憬的東西。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"다른 거라니?","JPN":"違うもの？","ENG":"Something other?","TWN":"你說有什麼不同？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"발생하잖아……. 현실에서도.","JPN":"発生するでしょ……現実でも。","ENG":"It occurs in reality... as well.","TWN":"發生了……在現實中。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"부정적인 감정으로 인한…… 침식 현상.","JPN":"ネガティブな感情による……侵食現象。","ENG":"A Counterside Effect... caused by negative emotions.","TWN":"由於負面情緒引起的……侵蝕現象。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"변하고 말 거야…… 카운터즈 레거시. 이면세계처럼.","JPN":"変わってしまう……カウンターズ・レガシー。裏世界みたいに。","ENG":"It will change... Counters Legacy. Like the Counterside.","TWN":"終將改變……制裁者的遺產，就像異界一樣。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"하지만 꺼야 해……. 급한 불부터.","JPN":"でも、解決しないと……急ぎの件から。","ENG":"We must take care... of the most urgent issue first.","TWN":"必須要處理……先從緊急的部分開始。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"내보내는 거야……. 유저들.","JPN":"追い出すよ……ユーザーたち。","ENG":"We have to force the users... to log out.","TWN":"要踢掉嗎……玩家。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"게임 내에서 일정 데미지를 받으면 무조건 로그아웃되는 시스템이었지?","JPN":"ゲーム内で一定のダメージを受けたら強制的にログアウトされるシステムよね？","ENG":"You're talking about the system where users are automatically logged out after taking a certain amount of damage, right?","TWN":"遊戲中受到一定傷害就會強制登出的系統，對吧？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"리네에게 연락할게. 분명 상황을 인지하고 있을 거야.","JPN":"マリちゃんに連絡するわ。きっと状況は把握しているはずよ。","ENG":"I'll contact Rinae. I'm sure she already knows what's going on.","TWN":"我來聯絡璃奈，她肯定已經知道情況了。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}}]`);export{e as default};